// Get raw Gemini response
const raw = $json.content.parts?.[0]?.text || "";

// Step 1: Remove markdown code block wrappers
let cleaned = raw
  .replace(/```json/g, "")
  .replace(/```/g, "")
  .trim();

// Step 2: Sometimes AI adds hidden spaces/newlines before JSON
cleaned = cleaned.replace(/^\s+|\s+$/g, "");

// Step 3: Parse JSON safely
let parsed;

try {
  parsed = JSON.parse(cleaned);
} catch (error) {
  throw new Error(
    "Failed to parse Gemini output as JSON. Raw output: " + cleaned
  );
}

// Step 4: Return structured output for next nodes
return [
  {
    json: {
      post: parsed.post,
      image_prompt: parsed.image_prompt
    }
  }
];

